const a=[{code:"AFR",name:"Authorization by FedRAMP",description:"FedRAMP authorization lifecycle — compliance monitoring, assessment scope, vulnerability assessment, security configuration guides, and data sharing.",ac3Narrative:"AC3 provides continuous compliance monitoring through the KSI Dashboard with automated validation scheduling, OSCAL-formatted evidence export for machine-readable data sharing, and full penetration testing across all 6 mandatory attack vectors to satisfy periodic vulnerability assessment requirements. The platform generates tamper-resistant evidence chains with SHA-256 integrity hashing, maintains version-controlled rules of engagement, and produces AI-powered assessment reports — covering the technical evidence generation that CSPs need for FedRAMP authorization.",ksiIds:["KSI-AFR-ADS","KSI-AFR-CCM","KSI-AFR-FSI","KSI-AFR-ICP","KSI-AFR-MAS","KSI-AFR-PVA","KSI-AFR-SCG","KSI-AFR-SCN"]},{code:"CMT",name:"Change Management",description:"Log and monitor modifications, validate changes through deployment, review change management procedures, and governance.",ac3Narrative:"AC3 records all security-relevant changes through its Audit Log with timestamps and user attribution, triggers post-deployment security validation through the Validation Scheduler, and tests detection coverage after changes using Agentless BAS and ATT&CK Validation Tests. The platform supports change management governance through version-controlled RoE documentation and scope enforcement, while Config Baseline Engine detects drift from approved configurations.",ksiIds:["KSI-CMT-LMC","KSI-CMT-RMV","KSI-CMT-RVP","KSI-CMT-VTD","KSI-CMT-CMG"]},{code:"CNA",name:"Cloud Native Architecture",description:"Minimal attack surface, secure-by-design architecture, encryption enforcement, network controls, cloud infrastructure hardening, and availability.",ac3Narrative:"AC3 continuously discovers the external attack surface through Domain Intel with Shodan, Censys, and SecurityTrails integrations. DigitalOcean infrastructure auditing validates cloud configurations across droplets, firewalls, load balancers, and databases. ZAP DAST validates TLS/encryption configurations, NGFW Validation tests network segmentation and firewall rules, and Cloud Attack Paths maps permission chains to identify architectural weaknesses.",ksiIds:["KSI-CNA-DFP","KSI-CNA-EDE","KSI-CNA-MAS","KSI-CNA-OFA","KSI-CNA-RNT","KSI-CNA-RVP","KSI-CNA-SBD","KSI-CNA-ULN","KSI-CNA-HCI","KSI-CNA-NSD"]},{code:"CED",name:"Cybersecurity Education",description:"Security awareness training effectiveness, developer training, incident response training, and high-risk role training.",ac3Narrative:"AC3 measures security awareness through realistic phishing campaigns with 17 exploit techniques including AiTM, BITB, device code phishing, and HTML smuggling. Purple Team exercises provide hands-on incident response training with measurable detection and response metrics. AD Attack Simulation targets privileged users for high-risk role training validation. DAST findings inform developer security training priorities.",ksiIds:["KSI-CED-RGT","KSI-CED-RRT","KSI-CED-RST","KSI-CED-DET"]},{code:"IAM",name:"Identity & Access Management",description:"Phishing-resistant MFA, privileged access management, least privilege enforcement, account lifecycle, JIT authorization, and service authentication.",ac3Narrative:"AC3 tests MFA resilience through real phishing campaigns with 17 MFA bypass techniques, validates privileged access controls through AD Attack Simulation, identifies excessive permissions through Cloud Attack Paths, and tests password policies through the Credential Attack Engine. AD Domain Connector enumerates accounts, group memberships, and privileged access for comprehensive IAM assessment.",ksiIds:["KSI-IAM-MFA","KSI-IAM-APM","KSI-IAM-ELP","KSI-IAM-PRA","KSI-IAM-AAM","KSI-IAM-JIT","KSI-IAM-SNU","KSI-IAM-SUS"]},{code:"INR",name:"Incident Response",description:"After-action reports, IR procedure review, incident pattern analysis, threat intelligence feeds, IOC management, and IR planning.",ac3Narrative:"AC3 generates comprehensive post-engagement reports with MITRE ATT&CK heatmaps and remediation recommendations. Purple Team exercises test IR procedures with measurable detection and response metrics. Real threat intelligence feeds from abuse.ch, Shodan, SecurityTrails, and DeHashed provide continuous threat data. IOC Feed manages indicators with automated enrichment, and Threat Actor Matcher correlates findings with known threat actor TTPs.",ksiIds:["KSI-INR-AAR","KSI-INR-RIR","KSI-INR-RPI","KSI-INR-IRP","KSI-INR-TIF","KSI-INR-TIU","KSI-INR-IOC"]},{code:"MLA",name:"Monitoring, Logging & Auditing",description:"Centralized SIEM operation, event type catalogs, configuration evaluation, log access controls, log review, and alert engineering.",ac3Narrative:"AC3 validates SIEM detection coverage through SIEM Connectors and Feedback Loop integration, auto-generates Sigma/YARA/Suricata detection rules from executed TTPs via the Detection Rule Generator, tests alert quality through the SIEM Mutation Engine, and measures detection coverage against MITRE techniques through the ATT&CK Coverage Matrix. Config Baseline Engine and SCAP Compliance Scanner evaluate security configurations against approved baselines.",ksiIds:["KSI-MLA-OSM","KSI-MLA-LET","KSI-MLA-EVC","KSI-MLA-ALE","KSI-MLA-ALA","KSI-MLA-RVL"]},{code:"PIY",name:"Policy & Inventory",description:"Real-time asset inventories, security investment review, SDLC security review, vulnerability disclosure programs, and executive support.",ac3Narrative:"AC3 generates real-time asset inventories through Domain Intel, Service Fingerprinting, and Web Crawler. Risk Trending and the Scoring Engine (CARVER+Shock/CVSS) provide quantifiable security investment ROI metrics. Bug Bounty Intelligence integrates HackerOne program data for vulnerability disclosure program oversight. DAST and API Security Testing validate SDLC security outputs.",ksiIds:["KSI-PIY-GIV","KSI-PIY-RIS","KSI-PIY-RSD","KSI-PIY-RVD","KSI-PIY-RES"]},{code:"RPL",name:"Recovery Planning",description:"Recovery plan alignment, RTO/RPO objectives, recovery capability testing, and disaster recovery planning.",ac3Narrative:"AC3's Config Baseline Engine can track whether recovery configurations align with stated objectives. Dedicated recovery validation testing with automated failover exercises is planned for future development. Recovery planning is primarily an organizational process outside the scope of an offensive security platform, but AC3 can verify configuration alignment.",ksiIds:["KSI-RPL-ARP","KSI-RPL-ABO","KSI-RPL-RRO","KSI-RPL-TRC"]},{code:"SVC",name:"Service Configuration",description:"Attack surface management, vulnerability scanning, configuration management, endpoint security, remediation management, and service transparency.",ac3Narrative:"AC3 provides comprehensive service configuration security through continuous attack surface management (Domain Intel + Shodan + Censys), real vulnerability scanning (ZAP DAST + Nuclei + scanner imports), risk-based vulnerability prioritization (CARVER+Shock/CVSS scoring with temporal decay), and full vulnerability lifecycle management including remediation verification and risk trending. DigitalOcean Infrastructure Audit validates cloud endpoint configurations.",ksiIds:["KSI-SVC-ASM","KSI-SVC-VSR","KSI-SVC-VRI","KSI-SVC-VCM","KSI-SVC-VRM","KSI-SVC-EIS","KSI-SVC-ACM","KSI-SVC-PRR","KSI-SVC-SNT"]},{code:"SCR",name:"Supply Chain Risk",description:"Penetration testing, APT simulation, security awareness testing, third-party vulnerability monitoring, and supply chain risk mitigation.",ac3Narrative:"AC3 delivers the core FedRAMP 20x penetration testing requirement through its multi-phase Engagement Pipeline with 16,000+ Metasploit modules. Adversary emulation with MITRE ATT&CK technique execution provides APT simulation. Phishing Ops with GoPhish integration delivers security awareness testing. NVD/KEV integration and Container Registry Scanner provide third-party vulnerability monitoring.",ksiIds:["KSI-SCR-PEN","KSI-SCR-APT","KSI-SCR-SAT","KSI-SCR-MON","KSI-SCR-MIT"]},{code:"SDE",name:"Secure Development",description:"Secure software testing and secure development practices validation.",ac3Narrative:"AC3 performs automated security testing of developed software through ZAP DAST for web application testing, API Security Testing for authentication and injection validation, and Nuclei Scanner for template-based security checks. DAST findings and vulnerability trend analysis inform secure development priorities by identifying common vulnerability classes.",ksiIds:["KSI-SDE-SST","KSI-SDE-SDP"]},{code:"PPM",name:"Policy & Procedure Management",description:"Policy and procedure review and implementation verification.",ac3Narrative:"AC3 supports policy documentation through version-controlled Rules of Engagement (RoE Builder) and tamper-resistant Evidence Chain storage. Scope Enforcement Middleware and Scan Policy Engine demonstrate policy implementation within the platform's operational scope. The platform supports policy documentation but organizational policy management remains outside its scope.",ksiIds:["KSI-PPM-PPR","KSI-PPM-PPI"]}],i=[{id:"KSI-AFR-ADS",name:"Authorization Data Sharing",themeCode:"AFR",coverageLevel:"supporting",requirement:"CSPs must share security authorization data with FedRAMP in machine-readable formats, enabling automated review and continuous monitoring of compliance posture across the authorization lifecycle.",howAC3Delivers:"AC3 generates machine-readable compliance evidence through three integrated systems. The OSCAL Export module produces FedRAMP-compliant OSCAL packages containing assessment results, findings, and control implementation details. The STIX Export module provides threat intelligence in standardized STIX 2.1 format for interoperability with government threat sharing platforms. The Evidence Chain maintains a tamper-resistant audit trail with SHA-256 integrity hashing, ensuring all shared data can be independently verified for authenticity.",aceModules:[{name:"OSCAL Export",role:"Produces machine-readable FedRAMP compliance packages in NIST OSCAL format for automated review"},{name:"STIX Export",role:"Generates standardized threat intelligence feeds in STIX 2.1 format for government interoperability"},{name:"Evidence Chain",role:"Maintains tamper-resistant audit trails with SHA-256 integrity hashing for data authenticity verification"}],evidenceTypes:["OSCAL assessment packages","STIX threat intelligence bundles","SHA-256 hash-chained evidence records"],validationMethod:"machine",frequency:"continuous",nistControls:["CA-7","SI-4"]},{id:"KSI-AFR-CCM",name:"Continuous Compliance Monitoring",themeCode:"AFR",coverageLevel:"direct",requirement:"CSPs must demonstrate continuous monitoring of security controls through automated evidence collection, scheduled assessments, and real-time compliance posture tracking — replacing point-in-time annual audits.",howAC3Delivers:"AC3 tracks all 75 Key Security Indicators through the KSI Dashboard with NIST SP 800-53 control mappings. The Validation Scheduler automates assessment cadence at configurable frequencies (3-day, 7-day, monthly), ensuring no KSI goes unvalidated past its required frequency. Auto-Collectors gather evidence from live API integrations including Shodan, Censys, abuse.ch, and NVD feeds, providing continuous real-world data rather than static documentation.",aceModules:[{name:"KSI Dashboard",role:"Tracks 75 Key Security Indicators with NIST SP 800-53 control mappings and real-time posture scoring"},{name:"Validation Scheduler",role:"Automates assessment cadence at configurable frequencies (3-day, 7-day, monthly) with overdue alerting"},{name:"Auto-Collectors",role:"Gathers evidence from live API integrations (Shodan, Censys, abuse.ch, NVD) for continuous monitoring"}],evidenceTypes:["KSI posture scores","Validation run results","Auto-collected evidence records","Overdue alerts"],validationMethod:"machine",frequency:"continuous",nistControls:["CA-7","CA-2"]},{id:"KSI-AFR-FSI",name:"FedRAMP Security Inbox",themeCode:"AFR",coverageLevel:"planned",requirement:"CSPs must maintain a dedicated communication channel for FedRAMP-related security correspondence with agencies and the PMO.",howAC3Delivers:"The platform notification system exists for operational alerts, but a dedicated FedRAMP communication channel for structured agency-CSP correspondence is planned for future development. Currently, security findings and assessment results can be exported and shared through OSCAL packages and evidence chain exports.",aceModules:[{name:"Notification System",role:"Provides operational alerting infrastructure that will be extended for FedRAMP communication"}],evidenceTypes:["Notification logs"],validationMethod:"n/a",frequency:"n/a",nistControls:["CA-7"]},{id:"KSI-AFR-ICP",name:"Initial Compliance Posture",themeCode:"AFR",coverageLevel:"supporting",requirement:"CSPs must document their initial security posture with traceable control mappings and evidence that security functions are operational from the start of the authorization process.",howAC3Delivers:"AC3's KSI Evidence Chain documents initial security posture with 142 NIST SP 800-53 control mappings across all 75 KSIs. Each piece of evidence is stored with integrity verification (SHA-256 hashing) for audit readiness. The initial posture assessment can be generated by running the full KSI validation suite and exporting results in OSCAL format.",aceModules:[{name:"KSI Evidence Chain",role:"Documents initial security posture with 142 NIST SP 800-53 control mappings and integrity verification"},{name:"NIST Control Mappings",role:"Maps all 75 KSIs to specific NIST SP 800-53 controls for FedRAMP traceability"}],evidenceTypes:["Initial posture assessment","NIST control mapping documentation","Evidence chain integrity records"],validationMethod:"mixed",frequency:"initial + annual",nistControls:["CA-2","PL-2"]},{id:"KSI-AFR-MAS",name:"Minimum Assessment Scope",themeCode:"AFR",coverageLevel:"direct",requirement:"CSPs must define and enforce assessment scope boundaries that cover all system components, ensuring no critical assets are excluded from security testing.",howAC3Delivers:"The RoE Builder defines and enforces assessment scope with version-controlled rules of engagement that specify authorized targets, testing windows, and escalation procedures. The Engagement Pipeline orchestrates multi-phase assessments (passive recon, active scanning, exploitation, reporting) ensuring comprehensive coverage. Scope Guard prevents out-of-scope testing by validating every scan target against approved boundaries before execution.",aceModules:[{name:"RoE Builder",role:"Defines version-controlled rules of engagement with authorized targets, testing windows, and escalation procedures"},{name:"Engagement Pipeline",role:"Orchestrates multi-phase assessments (passive → active → exploitation → reporting) for comprehensive coverage"},{name:"Scope Guard",role:"Validates every scan target against approved boundaries before execution to prevent out-of-scope testing"}],evidenceTypes:["RoE documentation","Scope boundary definitions","Assessment coverage reports","Scope violation logs"],validationMethod:"mixed",frequency:"per-engagement",nistControls:["CA-2","CA-8"]},{id:"KSI-AFR-PVA",name:"Periodic Vulnerability Assessment",themeCode:"AFR",coverageLevel:"direct",requirement:"CSPs must conduct regular vulnerability assessments using multiple scanning methodologies, covering web applications, infrastructure, and APIs with results tracked over time.",howAC3Delivers:"AC3 performs periodic vulnerability assessments through multiple complementary tools. ZAP DAST performs active web application testing with authenticated and unauthenticated scanning. Nuclei Scanner executes 9,000+ template-based vulnerability checks on remote scan servers via SSH. Vuln Scanner Import normalizes results from Nessus, Qualys, and Burp Suite into a unified format. The Engagement Pipeline orchestrates periodic assessment cycles with configurable scheduling.",aceModules:[{name:"ZAP DAST",role:"Performs active web application vulnerability scanning with authenticated and unauthenticated modes"},{name:"Nuclei Scanner",role:"Executes 9,000+ template-based vulnerability checks on remote scan servers via SSH"},{name:"Vuln Scanner Import",role:"Normalizes Nessus, Qualys, and Burp Suite results into a unified vulnerability format"},{name:"Engagement Pipeline",role:"Orchestrates periodic assessment cycles with configurable scheduling and multi-phase execution"}],evidenceTypes:["DAST scan results","Nuclei scan findings","Normalized scanner reports","Assessment timeline records"],validationMethod:"machine",frequency:"monthly",nistControls:["RA-5","CA-8"]},{id:"KSI-AFR-SCG",name:"Secure Configuration Guide",themeCode:"AFR",coverageLevel:"supporting",requirement:"CSPs must maintain secure configuration guides that define approved baselines for all system components and validate compliance against those baselines.",howAC3Delivers:"AC3's Config Baseline Engine tracks security configurations against approved baselines and detects drift from expected states. The SCAP Compliance Scanner checks CIS benchmarks for infrastructure security posture. These tools inform secure configuration guide development and validate compliance, but do not auto-generate the configuration guides themselves.",aceModules:[{name:"Config Baseline Engine",role:"Tracks security configurations against approved baselines and detects configuration drift"},{name:"SCAP Compliance Scanner",role:"Checks CIS benchmarks for infrastructure security posture against industry standards"}],evidenceTypes:["Configuration baseline reports","CIS benchmark compliance scores","Drift detection alerts"],validationMethod:"machine",frequency:"weekly",nistControls:["CM-6","CM-2"]},{id:"KSI-AFR-SCN",name:"Significant Change Notification",themeCode:"AFR",coverageLevel:"supporting",requirement:"CSPs must detect and report significant changes to their security posture, including configuration changes, new vulnerabilities, and infrastructure modifications.",howAC3Delivers:"The Audit Log records all security-relevant changes with timestamps, user attribution, and change details. The Config Baseline Engine detects drift from approved configurations, flagging significant deviations. The Evidence Chain provides tamper-resistant change records with SHA-256 integrity hashing, ensuring change history cannot be altered retroactively.",aceModules:[{name:"Audit Log",role:"Records all security-relevant changes with timestamps, user attribution, and change details"},{name:"Config Baseline Engine",role:"Detects drift from approved configurations and flags significant deviations"},{name:"Evidence Chain",role:"Provides tamper-resistant change records with SHA-256 integrity hashing"}],evidenceTypes:["Audit log entries","Configuration drift alerts","Integrity-verified change records"],validationMethod:"machine",frequency:"continuous",nistControls:["CM-3","CM-4"]},{id:"KSI-CMT-LMC",name:"Log and Monitor Modifications",themeCode:"CMT",coverageLevel:"direct",requirement:"All modifications to system components must be logged with timestamps, user attribution, and change details, with monitoring for unauthorized changes.",howAC3Delivers:"AC3's Audit Log records every security-relevant modification with timestamps, user attribution, and detailed change descriptions. The Evidence Chain stores modification records in a tamper-resistant format with SHA-256 integrity hashing, ensuring the modification history cannot be altered. Together, these provide a complete, verifiable record of all changes made through the platform.",aceModules:[{name:"Audit Log",role:"Records every security-relevant modification with timestamps, user attribution, and change details"},{name:"Evidence Chain",role:"Stores modification records in tamper-resistant format with SHA-256 integrity hashing"}],evidenceTypes:["Audit log entries","Integrity-verified modification records","Change timeline reports"],validationMethod:"machine",frequency:"continuous",nistControls:["CM-3","AU-2"]},{id:"KSI-CMT-RMV",name:"Redeployment of Version-Controlled Resources",themeCode:"CMT",coverageLevel:"supporting",requirement:"Infrastructure changes must be deployed through version-controlled, immutable deployment pipelines with rollback capabilities.",howAC3Delivers:"The Config Baseline Engine tracks deployment configurations and detects drift from approved baselines, verifying that deployments match expected states. The Audit Log records deployment events with version information. While AC3 does not manage Infrastructure-as-Code directly, it validates that deployed configurations match version-controlled baselines.",aceModules:[{name:"Config Baseline Engine",role:"Tracks deployment configurations and detects drift from approved baselines"},{name:"Audit Log",role:"Records deployment events with version information and timestamps"}],evidenceTypes:["Deployment configuration compliance reports","Baseline drift history","Deployment event logs"],validationMethod:"machine",frequency:"per-deployment",nistControls:["CM-2","CM-3"]},{id:"KSI-CMT-RVP",name:"Review Change Management Procedures",themeCode:"CMT",coverageLevel:"supporting",requirement:"Change management procedures must be documented, version-controlled, and periodically reviewed for effectiveness.",howAC3Delivers:"The Evidence Chain stores procedure documentation with version history and integrity verification. The RoE Builder maintains version-controlled rules of engagement that serve as operational change management documentation. LLM analysis can review procedures for completeness and identify gaps against FedRAMP requirements.",aceModules:[{name:"Evidence Chain",role:"Stores procedure documentation with version history and integrity verification"},{name:"RoE Builder",role:"Maintains version-controlled rules of engagement as operational change management documentation"}],evidenceTypes:["Procedure documentation","Version history records","Procedure review analysis"],validationMethod:"human",frequency:"quarterly",nistControls:["CM-1","CM-3"]},{id:"KSI-CMT-VTD",name:"Validate Changes Throughout Deployment",themeCode:"CMT",coverageLevel:"direct",requirement:"Security controls must be re-validated after every deployment to ensure changes have not introduced vulnerabilities or degraded security posture.",howAC3Delivers:"The Validation Scheduler triggers post-deployment security validation at configurable cadences, ensuring every change is followed by security re-testing. Agentless BAS tests detection coverage without deploying agents, verifying that security monitoring still functions after changes. ATT&CK Validation Tests confirm that security controls detect and respond to known attack techniques after deployment.",aceModules:[{name:"Validation Scheduler",role:"Triggers post-deployment security validation at configurable cadences"},{name:"Agentless BAS",role:"Tests detection coverage without deploying agents to verify monitoring after changes"},{name:"ATT&CK Validation Tests",role:"Confirms security controls detect known attack techniques after deployment"}],evidenceTypes:["Post-deployment validation results","BAS detection coverage reports","ATT&CK technique test results"],validationMethod:"machine",frequency:"per-deployment",nistControls:["CM-4","CA-2"]},{id:"KSI-CMT-CMG",name:"Change Management Governance",themeCode:"CMT",coverageLevel:"supporting",requirement:"Organizations must maintain governance structures for change management including approval workflows, documentation requirements, and compliance tracking.",howAC3Delivers:"The RoE Builder maintains version-controlled governance documentation with approval workflows. The Audit Log provides a complete change audit trail for governance oversight. Scope Guard enforces operational boundaries during testing, demonstrating governance enforcement. While AC3 supports governance documentation, it does not enforce organizational CM policy.",aceModules:[{name:"RoE Builder",role:"Maintains version-controlled governance documentation with approval workflows"},{name:"Audit Log",role:"Provides complete change audit trail for governance oversight"},{name:"Scope Guard",role:"Enforces operational boundaries during testing, demonstrating governance enforcement"}],evidenceTypes:["Governance documentation","Audit trail records","Scope enforcement logs"],validationMethod:"human",frequency:"quarterly",nistControls:["CM-1","CM-9"]},{id:"KSI-CNA-DFP",name:"Define Functionality and Privileges",themeCode:"CNA",coverageLevel:"direct",requirement:"Cloud environments must follow least-functionality principles with clearly defined privilege boundaries and minimal unnecessary services.",howAC3Delivers:"Cloud Attack Paths maps permission chains across cloud environments to identify over-privileged roles, unnecessary functionality, and excessive service exposure. AD Attack Simulation tests whether privilege boundaries are actually enforced by attempting escalation through discovered paths. Together, these prove whether environments follow least-functionality principles through real testing rather than documentation review.",aceModules:[{name:"Cloud Attack Paths",role:"Maps permission chains across cloud environments to identify over-privileged roles and unnecessary functionality"},{name:"AD Attack Simulation",role:"Tests whether privilege boundaries are enforced by attempting escalation through discovered paths"}],evidenceTypes:["Permission chain maps","Privilege escalation test results","Over-privileged role reports"],validationMethod:"machine",frequency:"monthly",nistControls:["AC-6","CM-7"]},{id:"KSI-CNA-EDE",name:"Encrypt Data at Rest and In Transit (FIPS)",themeCode:"CNA",coverageLevel:"supporting",requirement:"All data must be encrypted at rest and in transit using FIPS 140-2/3 validated cryptographic modules with proper key management.",howAC3Delivers:"ZAP DAST validates TLS configurations, cipher suites, and certificate validity across all endpoints, identifying weak encryption or misconfigured certificates. The Email Security Analyzer tests SPF, DKIM, and DMARC configurations for email encryption compliance. AC3 tests encryption implementation but does not implement encryption itself.",aceModules:[{name:"ZAP DAST",role:"Validates TLS configurations, cipher suites, and certificate validity across all endpoints"},{name:"Email Security Analyzer",role:"Tests SPF, DKIM, and DMARC configurations for email encryption compliance"}],evidenceTypes:["TLS configuration test results","Cipher suite analysis","Certificate validity reports","Email security scores"],validationMethod:"machine",frequency:"weekly",nistControls:["SC-13","SC-8"]},{id:"KSI-CNA-MAS",name:"Minimal Attack Surface",themeCode:"CNA",coverageLevel:"direct",requirement:"Organizations must continuously discover and minimize their external attack surface, identifying all exposed services, subdomains, and unnecessary endpoints.",howAC3Delivers:"Domain Intel discovers all external-facing assets, subdomains, and services using four integrated intelligence sources: Shodan for internet-wide scanning data, Censys for certificate and host discovery, SecurityTrails for DNS and domain intelligence, and URLScan for web content analysis. Service Fingerprinting identifies exposed services, technologies, and versions across the entire attack surface, enabling organizations to identify and remediate unnecessary exposure.",aceModules:[{name:"Domain Intel",role:"Discovers all external-facing assets and subdomains using Shodan, Censys, SecurityTrails, and URLScan"},{name:"Service Fingerprinting",role:"Identifies exposed services, technologies, and versions across the attack surface"},{name:"Shodan Integration",role:"Provides internet-wide scanning data for exposed services and banners"},{name:"Censys Integration",role:"Discovers certificates, hosts, and services through certificate transparency logs"}],evidenceTypes:["Attack surface discovery reports","Subdomain enumeration","Service exposure maps","Technology stack inventories"],validationMethod:"machine",frequency:"weekly",nistControls:["CM-7","RA-5"]},{id:"KSI-CNA-OFA",name:"Optimize for High Availability",themeCode:"CNA",coverageLevel:"planned",requirement:"Cloud architectures must be designed for high availability with redundancy, failover capabilities, and resilience against single points of failure.",howAC3Delivers:"The Config Baseline Engine can track high availability configurations against approved baselines. Active availability testing and failover validation is planned for future development. High availability optimization is primarily an infrastructure architecture concern that requires infrastructure-level testing capabilities.",aceModules:[{name:"Config Baseline Engine",role:"Tracks HA configurations against approved baselines (planned expansion)"}],evidenceTypes:["Configuration compliance reports"],validationMethod:"n/a",frequency:"n/a",nistControls:["CP-10","SC-5"]},{id:"KSI-CNA-RNT",name:"Restrict Network Traffic",themeCode:"CNA",coverageLevel:"supporting",requirement:"Network traffic must be restricted to authorized flows only, with firewall rules, security groups, and network ACLs properly configured and validated.",howAC3Delivers:"The DigitalOcean Firewall Audit (scanServer.doFirewallAudit) audits cloud firewall rules, port exposure, and droplet firewall coverage across the infrastructure. NGFW Validation tests next-generation firewall rules and network boundaries to verify that traffic restriction policies are actually enforced, not just configured.",aceModules:[{name:"DO Firewall Audit",role:"Audits cloud firewall rules, port exposure, and droplet firewall coverage"},{name:"NGFW Validation",role:"Tests next-generation firewall rules and network boundaries for enforcement effectiveness"}],evidenceTypes:["Firewall rule audit reports","Port exposure analysis","NGFW validation results"],validationMethod:"machine",frequency:"weekly",nistControls:["SC-7","AC-4"]},{id:"KSI-CNA-RVP",name:"Review DoS Protection Effectiveness",themeCode:"CNA",coverageLevel:"planned",requirement:"DoS protection mechanisms must be tested for effectiveness, including WAF rules, rate limiting, and DDoS mitigation services.",howAC3Delivers:"The Config Baseline Engine can track DoS protection configurations (WAF rules, rate limiting settings). Active DoS testing is out of scope for offensive security platforms due to the destructive nature of denial-of-service attacks. Configuration validation is available but active stress testing is not performed.",aceModules:[{name:"Config Baseline Engine",role:"Tracks DoS protection configurations including WAF rules and rate limiting (planned expansion)"}],evidenceTypes:["DoS protection configuration reports"],validationMethod:"n/a",frequency:"n/a",nistControls:["SC-5"]},{id:"KSI-CNA-SBD",name:"Secure By Design Architecture",themeCode:"CNA",coverageLevel:"supporting",requirement:"Cloud architectures must follow secure-by-design principles with defense-in-depth, zero trust, and security integrated into the architecture from inception.",howAC3Delivers:"Cloud Attack Paths identifies architectural security weaknesses by mapping permission chains, trust relationships, and lateral movement opportunities. SCAP Compliance Scanner checks CIS benchmarks for infrastructure security posture against industry-standard secure architecture requirements.",aceModules:[{name:"Cloud Attack Paths",role:"Identifies architectural security weaknesses through permission chain and trust relationship analysis"},{name:"SCAP Compliance Scanner",role:"Checks CIS benchmarks for infrastructure security posture against secure architecture standards"}],evidenceTypes:["Architecture weakness reports","Permission chain analysis","CIS benchmark compliance scores"],validationMethod:"mixed",frequency:"monthly",nistControls:["SA-8","SC-7"]},{id:"KSI-CNA-ULN",name:"Use Logical Networking Controls",themeCode:"CNA",coverageLevel:"supporting",requirement:"Logical networking controls including VPCs, security groups, and network ACLs must be properly configured to segment and protect cloud resources.",howAC3Delivers:"NGFW Validation tests firewall rules and network segmentation to verify that logical networking controls are properly enforced. The DigitalOcean Firewall Audit validates cloud-native networking controls, security group configurations, and outbound egress rules across the infrastructure.",aceModules:[{name:"NGFW Validation",role:"Tests firewall rules and network segmentation for enforcement effectiveness"},{name:"DO Firewall Audit",role:"Validates cloud-native networking controls, security groups, and egress rules"}],evidenceTypes:["Network segmentation test results","Security group audit reports","Egress rule validation"],validationMethod:"machine",frequency:"weekly",nistControls:["SC-7","AC-4"]},{id:"KSI-CNA-HCI",name:"Harden Cloud Infrastructure",themeCode:"CNA",coverageLevel:"direct",requirement:"Cloud infrastructure must be hardened against misconfigurations, with regular auditing of compute, network, database, and container resources.",howAC3Delivers:"The DigitalOcean Infrastructure Audit (scanServer.doInfraAudit) performs comprehensive checks across droplets, firewalls, load balancers, managed databases, DNS/domains, and Kubernetes clusters for security misconfigurations. Cloud Misconfiguration Detection via live KSI collectors identifies hardening gaps in real-time through continuous monitoring.",aceModules:[{name:"DO Infrastructure Audit",role:"Checks droplets, firewalls, load balancers, databases, DNS, and K8s clusters for misconfigurations"},{name:"Cloud Misconfiguration Detection",role:"Identifies hardening gaps in real-time through continuous monitoring via KSI collectors"}],evidenceTypes:["Infrastructure audit reports","Misconfiguration findings","Hardening compliance scores","Resource-level security assessments"],validationMethod:"machine",frequency:"weekly",nistControls:["CM-6","SC-7"]},{id:"KSI-CNA-NSD",name:"Network Segmentation & Defense",themeCode:"CNA",coverageLevel:"supporting",requirement:"Network segmentation must effectively isolate system components, with validation that segmentation boundaries prevent unauthorized lateral movement.",howAC3Delivers:"NGFW Validation tests network segmentation boundaries by attempting to traverse them, proving whether segmentation actually prevents unauthorized access. Service Fingerprinting identifies services that may cross segmentation boundaries, revealing potential segmentation violations. AC3 tests segmentation effectiveness but does not implement segmentation controls.",aceModules:[{name:"NGFW Validation",role:"Tests network segmentation boundaries by attempting to traverse them"},{name:"Service Fingerprinting",role:"Identifies services that may cross segmentation boundaries, revealing violations"}],evidenceTypes:["Segmentation boundary test results","Cross-boundary service discovery","Lateral movement test results"],validationMethod:"machine",frequency:"monthly",nistControls:["SC-7","AC-4"]},{id:"KSI-CED-RGT",name:"General Employee Training Effectiveness",themeCode:"CED",coverageLevel:"direct",requirement:"Security awareness training must be measurably effective, with phishing simulation results showing improvement over time and low click/credential-capture rates.",howAC3Delivers:"Phishing Ops executes realistic phishing campaigns with 17 exploit techniques including Adversary-in-the-Middle (AiTM) proxy, Browser-in-the-Browser (BITB), device code phishing, and HTML smuggling. Campaign Wizard configures targeted awareness exercises with customizable templates and delivery schedules. Results measure click rates, credential capture rates, reporting rates, and improvement trends across successive campaigns — providing quantifiable proof of training effectiveness.",aceModules:[{name:"Phishing Ops",role:"Executes realistic phishing campaigns with 17 exploit techniques including AiTM, BITB, and device code phishing"},{name:"Campaign Wizard",role:"Configures targeted awareness exercises with customizable templates and delivery schedules"},{name:"Template Generator",role:"Creates realistic phishing templates based on current threat landscape and organizational context"}],evidenceTypes:["Phishing campaign results","Click rate metrics","Credential capture rates","Improvement trend analysis"],validationMethod:"machine",frequency:"quarterly",nistControls:["AT-2","AT-3"]},{id:"KSI-CED-RRT",name:"IR/DR Staff Training Effectiveness",themeCode:"CED",coverageLevel:"supporting",requirement:"Incident response and disaster recovery staff must demonstrate training effectiveness through exercises that measure detection, containment, and communication capabilities.",howAC3Delivers:"Red Team Ops provides realistic attack scenarios for IR team training, creating real incidents that IR staff must detect and respond to. Purple Team exercises enable collaborative attack-defense training with measurable metrics. The SIEM Feedback Loop validates whether IR procedures detect real attacks during exercises, providing objective measurement of IR training effectiveness.",aceModules:[{name:"Red Team Ops",role:"Provides realistic attack scenarios for IR team training with real incidents to detect and respond to"},{name:"Purple Team",role:"Enables collaborative attack-defense training with measurable detection and response metrics"},{name:"SIEM Feedback Loop",role:"Validates whether IR procedures detect real attacks during exercises for objective measurement"}],evidenceTypes:["Purple Team exercise reports","Detection time metrics","Containment action records","SIEM alert coverage during exercises"],validationMethod:"mixed",frequency:"quarterly",nistControls:["AT-3","IR-2"]},{id:"KSI-CED-RST",name:"High-Risk Role Training Effectiveness",themeCode:"CED",coverageLevel:"supporting",requirement:"Personnel in high-risk roles (administrators, developers, security staff) must receive targeted training validated through role-specific security exercises.",howAC3Delivers:"AD Attack Simulation targets privileged accounts with techniques like Kerberoasting, Pass-the-Hash, and Golden Ticket attacks, testing whether high-risk users can be compromised. Phishing Ops can target high-risk roles specifically with tailored social engineering campaigns that match the sophistication level appropriate for their role.",aceModules:[{name:"AD Attack Simulation",role:"Targets privileged accounts with Kerberoasting, Pass-the-Hash, and Golden Ticket techniques"},{name:"Phishing Ops",role:"Targets high-risk roles with tailored social engineering campaigns matching role sophistication"}],evidenceTypes:["Privileged account compromise test results","Targeted phishing campaign results","Role-specific vulnerability reports"],validationMethod:"mixed",frequency:"quarterly",nistControls:["AT-3","AT-4"]},{id:"KSI-CED-DET",name:"Developer/Engineering Training Effectiveness",themeCode:"CED",coverageLevel:"planned",requirement:"Developer and engineering staff must demonstrate secure coding practices through reduced vulnerability rates in developed software.",howAC3Delivers:"DAST findings from ZAP can inform developer security training priorities by identifying common vulnerability classes (XSS, SQLi, IDOR) in developed applications. Vulnerability trend analysis over time shows whether developer training reduces common vulnerability classes. Dedicated developer training tracking and integration with secure coding platforms is planned.",aceModules:[{name:"ZAP DAST",role:"Identifies common vulnerability classes in developed applications to inform training priorities"}],evidenceTypes:["Vulnerability class trend analysis","DAST findings by vulnerability category"],validationMethod:"n/a",frequency:"n/a",nistControls:["AT-3","SA-11"]},{id:"KSI-IAM-MFA",name:"Phishing-Resistant MFA Enforcement",themeCode:"IAM",coverageLevel:"direct",requirement:"MFA must be enforced for all users with phishing-resistant methods (FIDO2, PIV) that cannot be bypassed by common social engineering techniques.",howAC3Delivers:"Phishing Ops executes real MFA bypass attacks including Adversary-in-the-Middle (AiTM) proxy that intercepts session tokens, Browser-in-the-Browser (BITB) that simulates fake login windows, device code phishing that exploits OAuth device flows, and HTML smuggling — 17 techniques total. Results prove whether MFA implementation actually resists real attack techniques, not just theoretical ones.",aceModules:[{name:"Phishing Ops",role:"Executes 17 real MFA bypass techniques including AiTM proxy, BITB, device code phishing, and HTML smuggling"},{name:"Campaign Wizard",role:"Configures MFA bypass campaigns with technique selection and targeting parameters"}],evidenceTypes:["MFA bypass test results","Technique success/failure rates","Session token interception attempts","Campaign analytics"],validationMethod:"machine",frequency:"quarterly",nistControls:["IA-2","IA-5"]},{id:"KSI-IAM-APM",name:"Authentication Policy Management",themeCode:"IAM",coverageLevel:"direct",requirement:"Authentication policies must enforce strong password requirements, account lockout thresholds, and session management controls.",howAC3Delivers:"Phishing Ops tests MFA bypass and credential harvesting to validate authentication policy enforcement. The Credential Attack Engine tests password policies by attempting dictionary attacks, brute force, and credential stuffing against authentication endpoints. Results validate lockout thresholds, password complexity enforcement, and authentication mechanism resilience.",aceModules:[{name:"Phishing Ops",role:"Tests MFA bypass and credential harvesting to validate authentication policy enforcement"},{name:"Credential Attack Engine",role:"Tests password policies, lockout thresholds, and authentication mechanisms through active testing"}],evidenceTypes:["Password policy test results","Lockout threshold validation","Credential attack success rates","Authentication mechanism analysis"],validationMethod:"machine",frequency:"quarterly",nistControls:["IA-5","AC-7"]},{id:"KSI-IAM-ELP",name:"Enforce Least Privilege",themeCode:"IAM",coverageLevel:"direct",requirement:"Access permissions must follow least privilege principles, with no users or services having more access than required for their function.",howAC3Delivers:"Cloud Attack Paths maps permission chains across cloud environments to identify over-privileged roles, unnecessary admin access, and excessive service permissions. AD Attack Simulation tests whether privilege boundaries are enforced by attempting escalation through discovered paths. The Privilege Escalation Engine automates discovery of escalation vectors across both cloud and on-premises environments.",aceModules:[{name:"Cloud Attack Paths",role:"Maps permission chains to identify over-privileged roles and excessive service permissions"},{name:"AD Attack Simulation",role:"Tests privilege boundary enforcement by attempting escalation through discovered paths"},{name:"Privilege Escalation Engine",role:"Automates discovery of escalation vectors across cloud and on-premises environments"}],evidenceTypes:["Permission chain maps","Privilege escalation test results","Over-privileged role reports","Escalation vector discovery"],validationMethod:"machine",frequency:"monthly",nistControls:["AC-6","AC-2"]},{id:"KSI-IAM-PRA",name:"Privileged Access Reviews & Auditing",themeCode:"IAM",coverageLevel:"direct",requirement:"Privileged accounts must be regularly reviewed and audited, with evidence of access reviews, group membership validation, and privileged activity monitoring.",howAC3Delivers:"AD Domain Connector enumerates the complete domain structure including group memberships, privileged accounts, service accounts, and last-login timestamps. Cloud Attack Paths identifies excessive cloud permissions and dormant privileged access. The Audit Log records all privileged access events within the platform for comprehensive activity monitoring.",aceModules:[{name:"AD Domain Connector",role:"Enumerates domain structure, group memberships, privileged accounts, and last-login timestamps"},{name:"Cloud Attack Paths",role:"Identifies excessive cloud permissions and dormant privileged access"},{name:"Audit Log",role:"Records all privileged access events for comprehensive activity monitoring"}],evidenceTypes:["Domain enumeration reports","Group membership analysis","Privileged account inventory","Access activity logs"],validationMethod:"mixed",frequency:"monthly",nistControls:["AC-2","AC-6"]},{id:"KSI-IAM-AAM",name:"Automated Account Lifecycle Management",themeCode:"IAM",coverageLevel:"supporting",requirement:"Account provisioning, modification, and deprovisioning must be automated with evidence of timely account lifecycle management.",howAC3Delivers:"AD Domain Connector enumerates accounts, group memberships, and last-login timestamps to identify stale or orphaned accounts that should have been deprovisioned. The Audit Log tracks account provisioning events within the platform. AC3 identifies lifecycle management issues but does not manage accounts directly.",aceModules:[{name:"AD Domain Connector",role:"Identifies stale/orphaned accounts through enumeration of last-login timestamps and group memberships"},{name:"Audit Log",role:"Tracks account provisioning events within the platform"}],evidenceTypes:["Stale account reports","Orphaned account discovery","Group membership sprawl analysis","Provisioning event logs"],validationMethod:"machine",frequency:"monthly",nistControls:["AC-2"]},{id:"KSI-IAM-JIT",name:"Just-In-Time Authorization",themeCode:"IAM",coverageLevel:"supporting",requirement:"Privileged access should be granted just-in-time rather than persistently, with evidence that standing admin access is minimized.",howAC3Delivers:"Cloud Attack Paths identifies persistent privileged access that should be JIT by mapping always-on admin permissions across cloud environments. The analysis reveals which accounts have standing admin access that could be converted to just-in-time authorization, reducing the attack surface.",aceModules:[{name:"Cloud Attack Paths",role:"Identifies persistent privileged access that should be converted to JIT authorization"}],evidenceTypes:["Persistent admin access reports","Standing privilege analysis","JIT conversion recommendations"],validationMethod:"machine",frequency:"monthly",nistControls:["AC-2","AC-6"]},{id:"KSI-IAM-SNU",name:"Secure Non-User Authentication",themeCode:"IAM",coverageLevel:"supporting",requirement:"Service accounts, API keys, and machine-to-machine authentication must be secured with proper credential management and rotation.",howAC3Delivers:"Service Fingerprinting identifies exposed service accounts and API endpoints across the attack surface. API Security Testing validates service-to-service authentication mechanisms, testing for weak API keys, missing authentication, and insecure token handling. AC3 tests service authentication but does not implement credential management.",aceModules:[{name:"Service Fingerprinting",role:"Identifies exposed service accounts and API endpoints across the attack surface"},{name:"API Security Testing",role:"Validates service-to-service authentication mechanisms and API key security"}],evidenceTypes:["Exposed service account reports","API authentication test results","Token handling analysis"],validationMethod:"machine",frequency:"monthly",nistControls:["IA-5","IA-9"]},{id:"KSI-IAM-SUS",name:"Suspend Suspicious Privileged Accounts",themeCode:"IAM",coverageLevel:"supporting",requirement:"Organizations must detect and respond to suspicious privileged account activity, including automated suspension of compromised accounts.",howAC3Delivers:"AD Attack Simulation identifies compromisable privileged accounts through techniques like Kerberoasting and Pass-the-Hash, revealing which accounts are vulnerable to compromise. Session Alerter detects suspicious activity patterns during red team exercises, testing whether the organization's monitoring detects account compromise. AC3 identifies suspicious accounts but does not suspend them.",aceModules:[{name:"AD Attack Simulation",role:"Identifies compromisable privileged accounts through Kerberoasting and Pass-the-Hash techniques"},{name:"Session Alerter",role:"Detects suspicious activity patterns during red team exercises to test monitoring effectiveness"}],evidenceTypes:["Compromisable account reports","Suspicious activity detection results","Red team exercise detection metrics"],validationMethod:"mixed",frequency:"quarterly",nistControls:["AC-2","SI-4"]},{id:"KSI-INR-AAR",name:"After-Action Reports and Lessons Learned",themeCode:"INR",coverageLevel:"direct",requirement:"Post-incident and post-exercise reports must document findings, root causes, lessons learned, and remediation recommendations with traceable evidence.",howAC3Delivers:"The Report Generator produces AI-powered post-engagement reports with a 13-section structure including executive summary, detailed findings, exploitation narrative, risk matrix, and remediation roadmap. Evidence Chain links all findings to proof artifacts with SHA-256 integrity verification. MITRE ATT&CK heatmaps visualize technique coverage and detection gaps.",aceModules:[{name:"Report Generator",role:"Produces AI-powered 13-section post-engagement reports with findings, risk matrix, and remediation roadmap"},{name:"Evidence Chain",role:"Links all findings to proof artifacts with SHA-256 integrity verification"},{name:"MITRE Heatmaps",role:"Visualizes ATT&CK technique coverage and detection gaps for lessons learned"}],evidenceTypes:["Post-engagement reports","MITRE ATT&CK heatmaps","Evidence-linked findings","Remediation roadmaps"],validationMethod:"mixed",frequency:"per-engagement",nistControls:["IR-4","IR-6"]},{id:"KSI-INR-RIR",name:"Review IR Procedures Effectiveness",themeCode:"INR",coverageLevel:"direct",requirement:"IR procedures must be tested through exercises that measure detection time, containment effectiveness, and communication during simulated incidents.",howAC3Delivers:"Purple Team exercises test whether IR procedures detect and respond to real attacks with measurable metrics including time-to-detect, time-to-contain, and communication effectiveness. The SIEM Feedback Loop validates whether SIEM rules fire during red team exercises, providing objective measurement of detection coverage. The Detection Rule Generator creates new rules from executed TTPs to improve detection for future incidents.",aceModules:[{name:"Purple Team",role:"Tests IR procedures with real attacks, measuring detection time, containment, and communication"},{name:"SIEM Feedback Loop",role:"Validates whether SIEM rules fire during red team exercises for objective detection measurement"},{name:"Detection Rule Generator",role:"Creates Sigma/YARA/Suricata rules from executed TTPs to improve future detection"}],evidenceTypes:["Purple Team exercise results","Detection time metrics","SIEM alert coverage reports","Generated detection rules"],validationMethod:"mixed",frequency:"quarterly",nistControls:["IR-3","IR-4"]},{id:"KSI-INR-RPI",name:"Review Past Incidents for Patterns",themeCode:"INR",coverageLevel:"supporting",requirement:"Organizations must analyze past incidents to identify patterns, recurring vulnerabilities, and threat actor trends that inform security improvements.",howAC3Delivers:"Threat Intel Connectors aggregate incident data from multiple sources for pattern analysis. Threat Actor Crawler identifies relevant threat actor patterns and TTPs. Ransomware Intel tracks ransomware group activity, targets, and techniques. Together, these provide the threat intelligence context needed to identify patterns across incidents.",aceModules:[{name:"Threat Intel Connectors",role:"Aggregates incident data from multiple sources for pattern analysis"},{name:"Threat Actor Crawler",role:"Identifies relevant threat actor patterns, TTPs, and targeting preferences"},{name:"Ransomware Intel",role:"Tracks ransomware group activity, targets, and techniques for trend analysis"}],evidenceTypes:["Threat intelligence reports","Threat actor TTP analysis","Ransomware trend data","Incident pattern analysis"],validationMethod:"mixed",frequency:"monthly",nistControls:["IR-4","SI-5"]},{id:"KSI-INR-IRP",name:"Incident Response Planning",themeCode:"INR",coverageLevel:"supporting",requirement:"Organizations must maintain and test incident response plans with defined roles, communication procedures, and escalation paths.",howAC3Delivers:"Red Team Ops provides realistic attack scenarios for IR planning validation, creating incidents that test plan effectiveness. The RoE Builder documents IR scope and rules of engagement with version control. Emulation Playbooks define repeatable attack scenarios for IR exercises, enabling consistent plan testing.",aceModules:[{name:"Red Team Ops",role:"Provides realistic attack scenarios for IR plan validation and testing"},{name:"RoE Builder",role:"Documents IR scope and rules of engagement with version control"},{name:"Emulation Playbooks",role:"Defines repeatable attack scenarios for consistent IR exercise execution"}],evidenceTypes:["Red team exercise scope documentation","IR plan test results","Emulation playbook execution records"],validationMethod:"human",frequency:"quarterly",nistControls:["IR-1","IR-8"]},{id:"KSI-INR-TIF",name:"Threat Intelligence Feeds",themeCode:"INR",coverageLevel:"direct",requirement:"Organizations must consume and integrate threat intelligence feeds from multiple sources to inform security operations and incident response.",howAC3Delivers:"AC3 integrates four real threat intelligence APIs: abuse.ch provides URLhaus malware URL feeds and ThreatFox IOC feeds; Shodan provides internet-wide scanning data and exposure intelligence; SecurityTrails provides DNS and domain intelligence with historical records; DeHashed provides credential breach data for exposure monitoring. All are live API integrations, not static data.",aceModules:[{name:"abuse.ch (URLhaus/ThreatFox)",role:"Provides malware URL feeds and IOC feeds from URLhaus and ThreatFox databases"},{name:"Shodan",role:"Provides internet-wide scanning data and exposure intelligence"},{name:"SecurityTrails",role:"Provides DNS and domain intelligence with historical records"},{name:"DeHashed",role:"Provides credential breach data for exposure monitoring"}],evidenceTypes:["Threat feed integration evidence","IOC ingestion logs","Feed freshness metrics","Threat data correlation reports"],validationMethod:"machine",frequency:"continuous",nistControls:["SI-5","PM-16"]},{id:"KSI-INR-TIU",name:"Threat Intelligence Utilization",themeCode:"INR",coverageLevel:"direct",requirement:"Threat intelligence must be actively utilized to inform security operations, testing priorities, and defensive improvements — not just collected.",howAC3Delivers:"Threat Actor Matcher correlates discovered vulnerabilities with known threat actor TTPs, showing which real-world adversaries could exploit each finding. Threat Enrichment Engine adds context to raw indicators by cross-referencing multiple intelligence sources. IOC Feed integrates indicators into operational workflows, ensuring threat data drives testing and remediation priorities.",aceModules:[{name:"Threat Actor Matcher",role:"Correlates vulnerabilities with known threat actor TTPs to show real-world exploitation risk"},{name:"Threat Enrichment Engine",role:"Adds context to raw indicators by cross-referencing multiple intelligence sources"},{name:"IOC Feed",role:"Integrates indicators into operational workflows to drive testing and remediation priorities"}],evidenceTypes:["Threat actor correlation reports","Enriched IOC records","Threat-informed testing priorities","TTP mapping evidence"],validationMethod:"machine",frequency:"continuous",nistControls:["SI-5","RA-3"]},{id:"KSI-INR-IOC",name:"Indicator of Compromise Management",themeCode:"INR",coverageLevel:"direct",requirement:"IOCs must be collected, enriched, stored, and operationalized with evidence of active indicator management and lifecycle tracking.",howAC3Delivers:"IOC Feed manages indicators with automated enrichment from abuse.ch and other sources, maintaining a current indicator database. Darkweb Intel monitors dark web sources for relevant IOCs including leaked credentials, exploit discussions, and threat actor communications. Threat Intel Ingest normalizes and stores indicators from multiple formats for operational use.",aceModules:[{name:"IOC Feed",role:"Manages indicators with automated enrichment from abuse.ch and other sources"},{name:"Darkweb Intel",role:"Monitors dark web sources for leaked credentials, exploit discussions, and threat actor communications"},{name:"Threat Intel Ingest",role:"Normalizes and stores indicators from multiple formats for operational use"}],evidenceTypes:["IOC database records","Enrichment logs","Dark web monitoring reports","Indicator lifecycle tracking"],validationMethod:"machine",frequency:"continuous",nistControls:["SI-5","IR-4"]},{id:"KSI-MLA-OSM",name:"Operate SIEM for Centralized Logging",themeCode:"MLA",coverageLevel:"direct",requirement:"A SIEM must be operational for centralized log collection, correlation, and alerting with evidence that it processes security events effectively.",howAC3Delivers:"SIEM Connectors integration tests connectivity and event forwarding to centralized SIEM platforms, verifying that the SIEM receives events from all critical sources. The SIEM Feedback Loop validates whether the SIEM actually processes and alerts on security events during red team exercises — proving the SIEM works, not just that it exists.",aceModules:[{name:"SIEM Connectors",role:"Tests connectivity and event forwarding to centralized SIEM platforms"},{name:"SIEM Feedback Loop",role:"Validates whether SIEM processes and alerts on security events during red team exercises"}],evidenceTypes:["SIEM connectivity test results","Event forwarding validation","Alert firing verification during exercises"],validationMethod:"machine",frequency:"weekly",nistControls:["AU-6","SI-4"]},{id:"KSI-MLA-LET",name:"Log Event Types Catalog",themeCode:"MLA",coverageLevel:"direct",requirement:"Organizations must maintain a catalog of logged event types with evidence that critical security events are captured and categorized.",howAC3Delivers:"SIEM Connectors define event types for platform activities, creating a baseline event catalog. The Detection Rule Generator produces Sigma/YARA/Suricata rules covering specific event types from executed TTPs, creating a comprehensive catalog of events that should be logged and alerted on based on real attack techniques.",aceModules:[{name:"SIEM Connectors",role:"Defines event types for platform activities, creating baseline event catalog"},{name:"Detection Rule Generator",role:"Produces detection rules covering specific event types from executed TTPs"}],evidenceTypes:["Event type catalog","Detection rule coverage maps","Event-to-technique mappings"],validationMethod:"machine",frequency:"monthly",nistControls:["AU-2","AU-3"]},{id:"KSI-MLA-EVC",name:"Evaluate and Test Configuration",themeCode:"MLA",coverageLevel:"direct",requirement:"Security configurations must be evaluated against approved baselines with evidence of regular testing and drift detection.",howAC3Delivers:"The Config Baseline Engine defines and monitors security configuration baselines, detecting drift from approved states. The SCAP Compliance Scanner checks CIS benchmarks for infrastructure security posture against industry-standard requirements. Results identify configuration drift and compliance gaps with actionable remediation guidance.",aceModules:[{name:"Config Baseline Engine",role:"Defines and monitors security configuration baselines with drift detection"},{name:"SCAP Compliance Scanner",role:"Checks CIS benchmarks for infrastructure security posture against industry standards"}],evidenceTypes:["Configuration baseline compliance reports","CIS benchmark scores","Drift detection alerts","Remediation guidance"],validationMethod:"machine",frequency:"weekly",nistControls:["CM-6","CM-3"]},{id:"KSI-MLA-ALE",name:"Alert Engineering & Response",themeCode:"MLA",coverageLevel:"direct",requirement:"Detection rules must be engineered, tested, and optimized with evidence that alerts are accurate, timely, and actionable.",howAC3Delivers:"The Detection Rule Generator creates Sigma, YARA, and Suricata rules from executed TTPs, ensuring detection rules are grounded in real attack techniques. The SIEM Mutation Engine tests alert quality by mutating attack patterns to verify rules detect variations, not just exact matches. The Sigma Rule Engine validates and optimizes detection rules for performance and accuracy.",aceModules:[{name:"Detection Rule Generator",role:"Creates Sigma/YARA/Suricata rules from executed TTPs grounded in real attack techniques"},{name:"SIEM Mutation Engine",role:"Tests alert quality by mutating attack patterns to verify rules detect variations"},{name:"Sigma Rule Engine",role:"Validates and optimizes detection rules for performance and accuracy"}],evidenceTypes:["Generated detection rules","Alert quality test results","Mutation test coverage","Rule optimization reports"],validationMethod:"machine",frequency:"monthly",nistControls:["SI-4","AU-6"]},{id:"KSI-MLA-ALA",name:"Access Controls for Log Data",themeCode:"MLA",coverageLevel:"supporting",requirement:"Log data must be protected with access controls that prevent unauthorized modification or deletion, with integrity verification.",howAC3Delivers:"The Evidence Chain provides tamper-resistant log storage with SHA-256 integrity verification, ensuring log data cannot be modified without detection. The Config Baseline Engine can track log access control configurations to verify proper access restrictions are in place.",aceModules:[{name:"Evidence Chain",role:"Provides tamper-resistant log storage with SHA-256 integrity verification"},{name:"Config Baseline Engine",role:"Tracks log access control configurations to verify proper access restrictions"}],evidenceTypes:["Log integrity verification records","Access control configuration reports","Tamper detection alerts"],validationMethod:"machine",frequency:"continuous",nistControls:["AU-9","AC-6"]},{id:"KSI-MLA-RVL",name:"Review and Audit Logs",themeCode:"MLA",coverageLevel:"supporting",requirement:"Log data must be regularly reviewed and audited with evidence that security events are analyzed and acted upon.",howAC3Delivers:"The ATT&CK Coverage Matrix measures detection coverage against MITRE techniques, revealing which logs are being reviewed effectively and where gaps exist. The SIEM Feedback Loop validates log review processes during exercises by confirming whether logged events trigger appropriate review and response actions.",aceModules:[{name:"ATT&CK Coverage Matrix",role:"Measures detection coverage against MITRE techniques to reveal log review effectiveness"},{name:"SIEM Feedback Loop",role:"Validates log review processes during exercises by confirming events trigger appropriate response"}],evidenceTypes:["ATT&CK detection coverage percentages","SIEM feedback loop results","Log review effectiveness metrics"],validationMethod:"mixed",frequency:"monthly",nistControls:["AU-6","AU-7"]},{id:"KSI-PIY-GIV",name:"Generate Real-Time Inventories",themeCode:"PIY",coverageLevel:"direct",requirement:"Organizations must maintain real-time, accurate inventories of all hardware, software, and cloud assets with automated discovery capabilities.",howAC3Delivers:"Domain Intel discovers all external-facing assets using four integrated intelligence sources: Shodan for internet-wide scanning, Censys for certificate and host discovery, SecurityTrails for DNS and domain intelligence, and URLScan for web content analysis. Service Fingerprinting identifies exposed services, technologies, and versions. Web Crawler maps application structure and content. Together, these produce a continuously-updated asset inventory.",aceModules:[{name:"Domain Intel",role:"Discovers all external-facing assets using Shodan, Censys, SecurityTrails, and URLScan"},{name:"Service Fingerprinting",role:"Identifies exposed services, technologies, and versions across the asset inventory"},{name:"Web Crawler",role:"Maps application structure and content for web asset inventory"}],evidenceTypes:["Asset discovery reports","Subdomain enumeration","Service inventory","Technology stack identification"],validationMethod:"machine",frequency:"weekly",nistControls:["CM-8","PM-5"]},{id:"KSI-PIY-RIS",name:"Review Security Investment Effectiveness",themeCode:"PIY",coverageLevel:"supporting",requirement:"Organizations must evaluate whether security investments are producing measurable improvements in security posture over time.",howAC3Delivers:"Risk Trending tracks historical risk trajectory, showing whether security investments reduce overall risk. The Scoring Engine (CARVER+Shock/CVSS) quantifies security posture with a composite score. Temporal Decay models score degradation over time, revealing whether investments maintain their value. These provide ROI metrics but don't evaluate investment decisions directly.",aceModules:[{name:"Risk Trending",role:"Tracks historical risk trajectory showing whether investments reduce overall risk"},{name:"Scoring Engine",role:"Quantifies security posture with CARVER+Shock/CVSS composite scoring"},{name:"Temporal Decay",role:"Models score degradation over time to reveal investment sustainability"}],evidenceTypes:["Risk trend reports","Security posture scores","Temporal decay analysis","ROI metrics"],validationMethod:"mixed",frequency:"quarterly",nistControls:["PM-4","PM-11"]},{id:"KSI-PIY-RSD",name:"Review SDLC Security (CISA Secure By Design)",themeCode:"PIY",coverageLevel:"supporting",requirement:"Organizations must review SDLC security practices against CISA Secure By Design principles, with evidence that development processes produce secure outputs.",howAC3Delivers:"ZAP DAST and API Security Testing validate SDLC security outputs by testing deployed applications for common vulnerability classes. Nuclei Scanner checks for known vulnerabilities in deployed software. Results inform SDLC security assessment but don't audit the SDLC process itself.",aceModules:[{name:"ZAP DAST",role:"Validates SDLC security outputs by testing deployed applications for common vulnerabilities"},{name:"API Security Testing",role:"Tests API security including authentication, authorization, and injection vulnerabilities"},{name:"Nuclei Scanner",role:"Checks for known vulnerabilities in deployed software using template-based scanning"}],evidenceTypes:["DAST scan results","API security test results","Vulnerability class trend analysis"],validationMethod:"machine",frequency:"monthly",nistControls:["SA-11","SA-15"]},{id:"KSI-PIY-RVD",name:"Review Vulnerability Disclosure Program",themeCode:"PIY",coverageLevel:"supporting",requirement:"Organizations must maintain and review vulnerability disclosure programs with evidence of program activity, submission handling, and resolution metrics.",howAC3Delivers:"Bug Bounty Intelligence integrates the HackerOne API to provide vulnerability disclosure program data including program activity, submission trends, severity distribution, and resolution metrics. This provides visibility into VDP effectiveness but doesn't manage the program itself.",aceModules:[{name:"Bug Bounty Intelligence (HackerOne)",role:"Integrates HackerOne API for VDP activity, submission trends, and resolution metrics"}],evidenceTypes:["VDP activity reports","Submission trend analysis","Resolution metrics","Severity distribution data"],validationMethod:"machine",frequency:"monthly",nistControls:["SI-2","PM-15"]},{id:"KSI-PIY-RES",name:"Review Executive Support for Security",themeCode:"PIY",coverageLevel:"planned",requirement:"Organizations must demonstrate executive-level support for security programs through documented governance, resource allocation, and strategic alignment.",howAC3Delivers:"This is an organizational governance requirement outside the scope of an offensive security platform. Executive support review requires organizational processes, board-level documentation, and resource allocation evidence that cannot be generated through security testing tools.",aceModules:[],evidenceTypes:[],validationMethod:"n/a",frequency:"n/a",nistControls:["PM-1","PM-2"]},{id:"KSI-RPL-ARP",name:"Align Recovery Plans with Objectives",themeCode:"RPL",coverageLevel:"supporting",requirement:"Recovery plans must align with business objectives, with evidence that recovery configurations match stated RTO/RPO requirements.",howAC3Delivers:"The Config Baseline Engine tracks whether recovery configurations align with stated objectives by monitoring backup configurations, replication settings, and failover parameters against approved baselines. The platform can verify configuration alignment but doesn't create recovery plans.",aceModules:[{name:"Config Baseline Engine",role:"Tracks recovery configurations against stated objectives and approved baselines"}],evidenceTypes:["Recovery configuration compliance reports","Baseline alignment verification"],validationMethod:"machine",frequency:"monthly",nistControls:["CP-2","CP-10"]},{id:"KSI-RPL-ABO",name:"Recovery Planning Alignment",themeCode:"RPL",coverageLevel:"planned",requirement:"Recovery planning must align with organizational objectives and be documented with clear roles, responsibilities, and communication procedures.",howAC3Delivers:"Recovery planning is an organizational process outside the scope of an offensive security platform. AC3 can validate recovery configurations through the Config Baseline Engine, but recovery plan development and organizational alignment require dedicated business continuity processes.",aceModules:[],evidenceTypes:[],validationMethod:"n/a",frequency:"n/a",nistControls:["CP-2"]},{id:"KSI-RPL-RRO",name:"Review RTO and RPO Objectives",themeCode:"RPL",coverageLevel:"planned",requirement:"Recovery time and recovery point objectives must be defined, documented, and validated through testing.",howAC3Delivers:"RTO/RPO measurement requires infrastructure-level testing capabilities (failover testing, backup restoration timing) that are outside the platform's scope. AC3 focuses on offensive security testing rather than infrastructure resilience validation.",aceModules:[],evidenceTypes:[],validationMethod:"n/a",frequency:"n/a",nistControls:["CP-2","CP-10"]},{id:"KSI-RPL-TRC",name:"Test Recovery Capabilities",themeCode:"RPL",coverageLevel:"planned",requirement:"Recovery capabilities must be tested through exercises that validate failover, backup restoration, and service continuity.",howAC3Delivers:"Automated failover and recovery testing requires infrastructure-level access outside the platform's scope. Recovery capability testing through disaster recovery exercises is planned for future development.",aceModules:[],evidenceTypes:[],validationMethod:"n/a",frequency:"n/a",nistControls:["CP-4","CP-10"]},{id:"KSI-SVC-ASM",name:"Attack Surface Management",themeCode:"SVC",coverageLevel:"direct",requirement:"Organizations must continuously discover, inventory, and manage their external attack surface including all exposed services, subdomains, and cloud resources.",howAC3Delivers:"Domain Intel discovers all external-facing assets using four integrated intelligence sources: Shodan for internet-wide scanning and banner grabbing, Censys for certificate transparency and host discovery, SecurityTrails for DNS intelligence and historical records, and URLScan for web content analysis. Service Fingerprinting identifies exposed services, technologies, and versions. Continuous discovery tracks attack surface changes over time, alerting on new exposure.",aceModules:[{name:"Domain Intel",role:"Discovers all external-facing assets using Shodan, Censys, SecurityTrails, and URLScan"},{name:"Shodan",role:"Provides internet-wide scanning data, banner grabbing, and exposure intelligence"},{name:"Censys",role:"Discovers certificates, hosts, and services through certificate transparency logs"},{name:"Service Fingerprinting",role:"Identifies exposed services, technologies, and versions across the attack surface"}],evidenceTypes:["Attack surface discovery reports","Subdomain enumeration","Service exposure maps","Change-over-time tracking"],validationMethod:"machine",frequency:"weekly",nistControls:["CM-8","RA-5"]},{id:"KSI-SVC-VSR",name:"Vulnerability Scanning Results",themeCode:"SVC",coverageLevel:"direct",requirement:"Regular vulnerability scanning must be performed across all system components with results tracked, prioritized, and remediated.",howAC3Delivers:"ZAP DAST performs active web application vulnerability scanning with authenticated and unauthenticated modes. Nuclei Scanner executes 9,000+ template-based vulnerability checks on remote scan servers via SSH. Vuln Scanner Import normalizes results from Nessus, Qualys, and Burp Suite into a unified format, enabling consolidated vulnerability management regardless of scanning tool.",aceModules:[{name:"ZAP DAST",role:"Performs active web application vulnerability scanning with authenticated and unauthenticated modes"},{name:"Nuclei Scanner",role:"Executes 9,000+ template-based vulnerability checks on remote scan servers via SSH"},{name:"Vuln Scanner Import",role:"Normalizes Nessus, Qualys, and Burp Suite results into a unified vulnerability format"}],evidenceTypes:["DAST scan results","Nuclei scan findings","Normalized multi-vendor scan reports","Vulnerability trend data"],validationMethod:"machine",frequency:"monthly",nistControls:["RA-5","SI-2"]},{id:"KSI-SVC-VRI",name:"Vulnerability Risk Identification",themeCode:"SVC",coverageLevel:"direct",requirement:"Vulnerabilities must be risk-ranked using a consistent methodology that considers exploitability, impact, and business context.",howAC3Delivers:"The Scoring Engine combines CARVER+Shock methodology with CVSS for multi-dimensional vulnerability prioritization that considers criticality, accessibility, recuperability, vulnerability, effect, and recognizability. Temporal Decay models score degradation over time, ensuring aging vulnerabilities are re-prioritized. Risk Trending tracks historical risk trajectory for trend analysis and remediation effectiveness measurement.",aceModules:[{name:"Scoring Engine (CARVER+Shock/CVSS)",role:"Multi-dimensional vulnerability prioritization combining CARVER+Shock with CVSS"},{name:"Temporal Decay",role:"Models score degradation over time to re-prioritize aging vulnerabilities"},{name:"Risk Trending",role:"Tracks historical risk trajectory for trend analysis and remediation measurement"}],evidenceTypes:["Risk-ranked vulnerability reports","CARVER+Shock scores","Temporal decay analysis","Risk trend data"],validationMethod:"machine",frequency:"continuous",nistControls:["RA-3","RA-5"]},{id:"KSI-SVC-VCM",name:"Vulnerability/Configuration Management",themeCode:"SVC",coverageLevel:"direct",requirement:"Vulnerability and configuration management must be integrated with evidence of continuous vulnerability intelligence, scan normalization, and remediation tracking.",howAC3Delivers:"Vuln Feeds aggregate NVD and CISA KEV data for continuous vulnerability intelligence, ensuring the platform tracks the latest known vulnerabilities. Vuln Scanner Import normalizes multi-vendor scan results into a unified format. Remediation Verification tracks and validates fix implementation through re-scanning, closing the vulnerability management loop.",aceModules:[{name:"Vuln Feeds (NVD/KEV)",role:"Aggregates NVD and CISA KEV data for continuous vulnerability intelligence"},{name:"Vuln Scanner Import",role:"Normalizes multi-vendor scan results into a unified vulnerability format"},{name:"Remediation Verification",role:"Tracks and validates fix implementation through re-scanning"}],evidenceTypes:["NVD/KEV integration evidence","Normalized scan reports","Remediation tracking records","Fix verification results"],validationMethod:"machine",frequency:"continuous",nistControls:["SI-2","CM-6"]},{id:"KSI-SVC-VRM",name:"Vulnerability Remediation Management",themeCode:"SVC",coverageLevel:"direct",requirement:"Vulnerability remediation must be tracked with evidence of fix implementation, re-validation, and risk reduction over time.",howAC3Delivers:"Remediation Verification tracks remediation progress and validates fixes through re-scanning, confirming that vulnerabilities are actually resolved rather than just marked as fixed. Risk Trending shows whether remediation efforts reduce overall risk over time, providing evidence of remediation effectiveness.",aceModules:[{name:"Remediation Verification",role:"Tracks remediation progress and validates fixes through re-scanning"},{name:"Risk Trending",role:"Shows whether remediation efforts reduce overall risk over time"}],evidenceTypes:["Remediation tracking reports","Re-scan validation results","Risk reduction trend data","Fix implementation rates"],validationMethod:"machine",frequency:"monthly",nistControls:["SI-2","RA-5"]},{id:"KSI-SVC-EIS",name:"Endpoint/Infrastructure Security",themeCode:"SVC",coverageLevel:"direct",requirement:"Endpoint and infrastructure security must be validated through scanning, configuration auditing, and vulnerability assessment.",howAC3Delivers:"Nuclei Scanner tests endpoint security with 9,000+ template-based vulnerability checks. Vuln Scanner Import processes endpoint scan results from multiple vendors. The DigitalOcean Infrastructure Audit validates cloud endpoint configurations across droplets, firewalls, load balancers, managed databases, and Kubernetes clusters.",aceModules:[{name:"Nuclei Scanner",role:"Tests endpoint security with 9,000+ template-based vulnerability checks"},{name:"Vuln Scanner Import",role:"Processes endpoint scan results from Nessus, Qualys, and Burp Suite"},{name:"DO Infrastructure Audit",role:"Validates cloud endpoint configurations across droplets, firewalls, LBs, databases, and K8s"}],evidenceTypes:["Endpoint scan results","Infrastructure audit reports","Cloud configuration assessments","Vulnerability findings"],validationMethod:"machine",frequency:"weekly",nistControls:["SI-2","CM-6"]},{id:"KSI-SVC-ACM",name:"Automated Configuration Management",themeCode:"SVC",coverageLevel:"supporting",requirement:"Configuration management must be automated with evidence of baseline enforcement, drift detection, and compliance monitoring.",howAC3Delivers:"The Config Baseline Engine tracks configurations against approved baselines and detects drift from expected states. The SCAP Compliance Scanner checks CIS benchmarks for infrastructure security posture. The platform monitors configurations but doesn't manage them directly — it identifies drift and compliance gaps.",aceModules:[{name:"Config Baseline Engine",role:"Tracks configurations against approved baselines and detects drift"},{name:"SCAP Compliance Scanner",role:"Checks CIS benchmarks for infrastructure security posture"}],evidenceTypes:["Configuration baseline compliance reports","CIS benchmark scores","Drift detection alerts"],validationMethod:"machine",frequency:"weekly",nistControls:["CM-2","CM-6"]},{id:"KSI-SVC-PRR",name:"Post-Change Residual Review",themeCode:"SVC",coverageLevel:"supporting",requirement:"After changes are deployed, residual security risks must be identified through post-change validation and re-testing.",howAC3Delivers:"The Validation Scheduler can trigger post-change re-validation to identify residual risks after changes, ensuring that security controls still function correctly. The platform tests for residual issues but doesn't manage the change process itself.",aceModules:[{name:"Validation Scheduler",role:"Triggers post-change re-validation to identify residual security risks"}],evidenceTypes:["Post-change validation results","Residual risk identification reports"],validationMethod:"machine",frequency:"per-change",nistControls:["CM-4","CA-2"]},{id:"KSI-SVC-SNT",name:"Service Notification/Transparency",themeCode:"SVC",coverageLevel:"planned",requirement:"Organizations must maintain transparency about service status, incidents, and changes through notification mechanisms.",howAC3Delivers:"Service notification and transparency requires organizational communication processes outside the platform's scope. AC3's notification system provides operational alerting but dedicated service status communication is planned for future development.",aceModules:[],evidenceTypes:[],validationMethod:"n/a",frequency:"n/a",nistControls:["IR-6","SI-5"]},{id:"KSI-SCR-PEN",name:"Penetration Testing",themeCode:"SCR",coverageLevel:"direct",requirement:"CSPs must conduct comprehensive penetration testing across all 6 FedRAMP mandatory attack vectors: external, internal, web application, API, mobile, and social engineering.",howAC3Delivers:"The Engagement Pipeline orchestrates multi-phase penetration tests through four stages: passive reconnaissance, active scanning, exploitation, and reporting. The Exploit Arsenal provides access to 16,000+ Metasploit modules for comprehensive exploitation testing. ZAP DAST and Nuclei Scanner perform automated vulnerability discovery across web applications and infrastructure. Results are compiled into AI-powered reports with MITRE ATT&CK heatmaps and remediation recommendations.",aceModules:[{name:"Engagement Pipeline",role:"Orchestrates multi-phase penetration tests (recon → scanning → exploitation → reporting)"},{name:"Exploit Arsenal",role:"Provides 16,000+ Metasploit modules for comprehensive exploitation testing"},{name:"ZAP DAST",role:"Performs automated web application vulnerability discovery and testing"},{name:"Nuclei Scanner",role:"Executes template-based vulnerability checks across infrastructure"}],evidenceTypes:["Penetration test reports","Exploitation evidence","MITRE ATT&CK heatmaps","Remediation recommendations"],validationMethod:"mixed",frequency:"annual + per-significant-change",nistControls:["CA-8","RA-5"]},{id:"KSI-SCR-APT",name:"Advanced Persistent Threat Simulation",themeCode:"SCR",coverageLevel:"direct",requirement:"Organizations must simulate APT-level attacks to test detection and response capabilities against sophisticated, multi-stage threat actors.",howAC3Delivers:"AC3 Emulation provides full adversary emulation with MITRE ATT&CK technique execution across the kill chain — from initial access through lateral movement to data exfiltration. Emulation Playbooks define repeatable APT scenarios based on real threat actor TTPs. Threat Actor Matcher correlates findings with known threat actor capabilities, showing which real-world adversaries could exploit discovered weaknesses.",aceModules:[{name:"AC3 Emulation",role:"Provides full adversary emulation with MITRE ATT&CK technique execution across the kill chain"},{name:"Emulation Playbooks",role:"Defines repeatable APT scenarios based on real threat actor TTPs"},{name:"Threat Actor Matcher",role:"Correlates findings with known threat actor capabilities and TTPs"}],evidenceTypes:["APT simulation results","MITRE ATT&CK technique coverage","Detection rate metrics","Threat actor TTP correlation"],validationMethod:"mixed",frequency:"quarterly",nistControls:["CA-8","SI-4"]},{id:"KSI-SCR-SAT",name:"Security Awareness Testing",themeCode:"SCR",coverageLevel:"direct",requirement:"Security awareness must be tested through realistic social engineering campaigns that measure employee susceptibility and improvement over time.",howAC3Delivers:"Phishing Ops executes realistic social engineering campaigns via GoPhish integration with 17 exploit techniques including AiTM proxy, BITB, device code phishing, and HTML smuggling. Campaign Wizard configures multi-step campaigns with customizable templates and delivery schedules. Results measure click rates, credential capture rates, MFA bypass success, and improvement trends across successive campaigns.",aceModules:[{name:"Phishing Ops",role:"Executes realistic social engineering campaigns with 17 exploit techniques via GoPhish"},{name:"Campaign Wizard",role:"Configures multi-step campaigns with customizable templates and delivery schedules"},{name:"GoPhish",role:"Provides campaign infrastructure for phishing simulation and tracking"}],evidenceTypes:["Phishing campaign results","Click rate metrics","Credential capture rates","Improvement trend analysis"],validationMethod:"machine",frequency:"quarterly",nistControls:["AT-2","AT-3"]},{id:"KSI-SCR-MON",name:"Monitor Third-Party Software Vulnerabilities",themeCode:"SCR",coverageLevel:"direct",requirement:"Third-party software vulnerabilities must be continuously monitored with evidence of NVD/KEV integration and dependency scanning.",howAC3Delivers:"Vuln Feeds aggregate NVD and CISA KEV data for continuous third-party vulnerability monitoring, ensuring the platform tracks all known vulnerabilities in third-party components. Container Registry Scanner checks container images for known vulnerabilities in dependencies, identifying vulnerable libraries and frameworks.",aceModules:[{name:"Vuln Feeds (NVD/KEV)",role:"Aggregates NVD and CISA KEV data for continuous third-party vulnerability monitoring"},{name:"Container Registry Scanner",role:"Checks container images for known vulnerabilities in dependencies"}],evidenceTypes:["NVD/KEV monitoring evidence","Container image scan results","Dependency vulnerability reports"],validationMethod:"machine",frequency:"continuous",nistControls:["RA-5","SI-2"]},{id:"KSI-SCR-MIT",name:"Mitigate Supply Chain Risks",themeCode:"SCR",coverageLevel:"supporting",requirement:"Supply chain risks must be identified and mitigated with evidence of dependency analysis, vulnerability tracking, and risk reduction.",howAC3Delivers:"Container Registry Scanner identifies vulnerable dependencies in container images, revealing supply chain risks from third-party components. Nuclei Scanner tests for known supply chain vulnerabilities in deployed software. The platform identifies supply chain risks but doesn't implement supply chain controls like vendor management or procurement security.",aceModules:[{name:"Container Registry Scanner",role:"Identifies vulnerable dependencies in container images for supply chain risk"},{name:"Nuclei Scanner",role:"Tests for known supply chain vulnerabilities in deployed software"}],evidenceTypes:["Container dependency analysis","Supply chain vulnerability reports","Third-party risk identification"],validationMethod:"machine",frequency:"monthly",nistControls:["SR-3","SR-6"]},{id:"KSI-SDE-SST",name:"Secure Software Testing",themeCode:"SDE",coverageLevel:"direct",requirement:"Software must undergo automated security testing including DAST, API security testing, and template-based vulnerability scanning before and after deployment.",howAC3Delivers:"ZAP DAST performs active web application security testing with both authenticated and unauthenticated scanning modes, covering OWASP Top 10 and beyond. API Security Testing validates API security including authentication bypass, authorization flaws, injection vulnerabilities, and rate limiting. Nuclei Scanner executes template-based security checks against deployed applications. All produce real vulnerability data with evidence artifacts.",aceModules:[{name:"ZAP DAST",role:"Performs active web application security testing covering OWASP Top 10 and beyond"},{name:"API Security Testing",role:"Validates API security: authentication, authorization, injection, and rate limiting"},{name:"Nuclei Scanner",role:"Executes template-based security checks against deployed applications"}],evidenceTypes:["DAST scan results","API security test findings","Nuclei scan reports","Vulnerability evidence artifacts"],validationMethod:"machine",frequency:"per-release + monthly",nistControls:["SA-11","SI-2"]},{id:"KSI-SDE-SDP",name:"Secure Development Practices",themeCode:"SDE",coverageLevel:"supporting",requirement:"Development practices must produce secure software, with evidence that common vulnerability classes decrease over time as practices mature.",howAC3Delivers:"DAST findings from ZAP and Vuln Analysis Agents inform secure development priorities by identifying common vulnerability classes (XSS, SQLi, IDOR, SSRF) in deployed applications. Vulnerability trend analysis over time shows whether secure development practices are reducing common vulnerability classes. The platform tests development outputs but doesn't audit SDLC processes directly.",aceModules:[{name:"ZAP DAST",role:"Identifies common vulnerability classes in deployed applications to measure development security"},{name:"Vuln Analysis Agents",role:"Analyzes vulnerability patterns to inform secure development priorities"}],evidenceTypes:["Vulnerability class trend analysis","Common vulnerability category reports","Development security metrics"],validationMethod:"mixed",frequency:"quarterly",nistControls:["SA-11","SA-15"]},{id:"KSI-PPM-PPR",name:"Policy & Procedure Review",themeCode:"PPM",coverageLevel:"supporting",requirement:"Security policies and procedures must be documented, version-controlled, and periodically reviewed for completeness and effectiveness.",howAC3Delivers:"The RoE Builder maintains version-controlled rules of engagement and policy documents with full revision history. The Evidence Chain stores policy documentation with SHA-256 integrity verification, ensuring documents cannot be altered without detection. LLM analysis can review policies for completeness against FedRAMP requirements.",aceModules:[{name:"RoE Builder",role:"Maintains version-controlled rules of engagement and policy documents with revision history"},{name:"Evidence Chain",role:"Stores policy documentation with SHA-256 integrity verification"}],evidenceTypes:["Policy documentation","Version history records","Integrity verification records","Policy review analysis"],validationMethod:"human",frequency:"annual",nistControls:["PL-1","PL-2"]},{id:"KSI-PPM-PPI",name:"Policy & Procedure Implementation",themeCode:"PPM",coverageLevel:"supporting",requirement:"Policies and procedures must be implemented with evidence that operational practices align with documented policies.",howAC3Delivers:"Scope Enforcement Middleware enforces operational boundaries during testing, demonstrating that policies are implemented in practice — not just documented. The Scan Policy Engine defines and enforces scan policies including authorized techniques, timing restrictions, and escalation procedures. These demonstrate policy implementation within the platform's operational scope.",aceModules:[{name:"Scope Enforcement Middleware",role:"Enforces operational boundaries during testing, demonstrating policy implementation"},{name:"Scan Policy Engine",role:"Defines and enforces scan policies including techniques, timing, and escalation procedures"}],evidenceTypes:["Scope enforcement logs","Scan policy compliance records","Operational policy enforcement evidence"],validationMethod:"machine",frequency:"continuous",nistControls:["PL-2","PM-1"]}],t=new Map;for(const e of i)t.set(e.id,e);const n=new Map;for(const e of a)n.set(e.code,e);function r(e){return t.get(e)}function s(e){return n.get(e)}function o(e){switch(e){case"direct":return"bg-emerald-500/20 text-emerald-400 border-emerald-500/30";case"supporting":return"bg-amber-500/20 text-amber-400 border-amber-500/30";case"planned":return"bg-slate-500/20 text-slate-400 border-slate-500/30"}}i.length,i.filter(e=>e.coverageLevel==="direct").length,i.filter(e=>e.coverageLevel==="supporting").length,i.filter(e=>e.coverageLevel==="planned").length;export{s as a,o as b,r as g};
